function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		setInfoMessage();
		return;
	}

	function setInfoMessage() {
		g_form.showFieldMsg('u_order', getMessage('Tasker - Info Message - Order will set priority with highest order number first'), 'info');
	}
}
